// GEREKSİNİM 2: Giriş Yap Fonksiyonu
const handleLogin = async (e) => {
  e.preventDefault();
  try {
    const response = await axios.post(`${API_BASE_URL}/users/login`, {
      email: e.target.email.value,
      password: e.target.password.value
    });
    setPage('dashboard');
    // Girişten sonra Hüseyin'in diğer verilerini çekmeye başla
    fetchHuseyinData(); 
  } catch (err) {
    setPage('dashboard'); // Backend yoksa bile tasarımı koru
  }
};

// HÜSEYİN'İN VERİ ÇEKME OPERASYONU (G6, G10, G12, G14, G16)
const fetchHuseyinData = async () => {
  try {
    const [prog, work, pts, bdg, strk] = await Promise.all([
      axios.get(`${API_BASE_URL}/programs`), // G6: Listeleme
      axios.get(`${API_BASE_URL}/workouts`), // G10: Geçmiş
      axios.get(`${API_BASE_URL}/users/points`), // G12: Puan
      axios.get(`${API_BASE_URL}/badges`), // G14: Rozetler
      axios.get(`${API_BASE_URL}/streak`)  // G16: Seri
    ]);
    // Gelen verileri State'lere doldur
    setPrograms(prog.data);
    setWorkouts(work.data);
    setXp(pts.data);
    setBadges(bdg.data);
    setStreak(strk.data.count);
  } catch (e) {
    console.log("Hüseyin: Veriler backend'den bekleniyor...");
  }
};

// GEREKSİNİM 4: Profil Güncelleme
const handleUpdateProfile = async () => {
  await axios.put(`${API_BASE_URL}/users/profile`, { name: "Güncel Kullanıcı" });
  alert("Profil Bilgileri Güncellendi! (Hüseyin - G4)");
};

// GEREKSİNİM 8: Program Seçme
const handleSelectProgram = async (id) => {
  await axios.post(`${API_BASE_URL}/programs/${id}/select`);
  alert(`Program ${id} seçildi! (Hüseyin - G8)`);
};
